function Get-WingetPath {
    # 1) Try PATH
    $cmd = Get-Command winget -ErrorAction SilentlyContinue
    if ($cmd -and (Test-Path $cmd.Source)) { return $cmd.Source }

    # 2) Try user WindowsApps (works in normal user context)
    $p1 = Join-Path $env:LOCALAPPDATA 'Microsoft\WindowsApps\winget.exe'
    if (Test-Path $p1) { return $p1 }

    # 3) Try SYSTEM-style WindowsApps install location (common in unattended contexts)
    $candidates = Get-ChildItem "C:\Program Files\WindowsApps\Microsoft.DesktopAppInstaller_*_x64__8wekyb3d8bbwe\winget.exe" -ErrorAction SilentlyContinue |
        Sort-Object FullName -Descending
    if ($candidates -and (Test-Path $candidates[0].FullName)) { return $candidates[0].FullName }

    return $null
}

while ($true) {
    $winget = Get-WingetPath

    if ($winget) {
        Write-Host "Using winget: $winget"

        # Refresh sources (helps a lot in fresh installs)
        & $winget source update --accept-source-agreements | Out-Host

        foreach ($id in $packages) {
            Write-Host "Installing $id ..."

            # If already installed, winget will often return a non-zero exit code.
            # We treat that as "warn but continue".
            & $winget install `
                --exact --id $id `
                --silent `
                --accept-package-agreements --accept-source-agreements `
                --source winget `
                --scope machine

            if ($LASTEXITCODE -ne 0) {
                Write-Warning "winget install exit code $LASTEXITCODE for $id (may already be installed or needs interaction)."
            } else {
                Write-Host "Installed $id"
            }
        }

        # Upgrade everything possible (this is the command you want)
        Write-Host "Upgrading all packages..."
        & $winget upgrade --all --silent --accept-package-agreements --accept-source-agreements

        if ($LASTEXITCODE -ne 0) {
            Write-Warning "winget upgrade --all exit code $LASTEXITCODE"
        } else {
            Write-Host "Upgrade complete."
        }

        return
    }

    if ([datetime]::Now -gt $timeout) {
        Write-Warning "winget.exe not found within timeout. (Often means App Installer/winget isn't installed yet in this context.)"
        return
    }

    Write-Host "Waiting for winget to become available..."
    Start-Sleep -Seconds 2
}

